const item = $('Text Pipeline Input').first().json;
const order = item.order || {};
const jobId = item.jobId || 'ft_' + Date.now();
const requestedWorldKey = order.world || 'romantic_story';
const worldAliases = { new_year: 'hogwarts_world', disney_light: 'romantic_story' };
const worldKey = worldAliases[requestedWorldKey] || requestedWorldKey;
const chaptersTarget = Math.max(1, Math.min(8, Number(order.chapters || 5)));
const lengthTarget = Math.max(2500, Number(order.lengthTarget || 15000));
const chapterTextBlockTargets = { 1: 4, 2: 4, 3: 6, 4: 6, 5: 5 };
const firstChapterTextBlockTarget = chapterTextBlockTargets[1] || 4;
const chapterNumbers = Array.from({ length: chaptersTarget }, (_, index) => index + 1);
const planShape = chapterNumbers.map((n) => '{ "n": ' + n + ', "title": "...", "beat": "..." }').join(', ');
const laterChaptersText = chaptersTarget > 1 ? 'краткий план 2-' + chaptersTarget + ' глав' : 'только финальный вектор истории без дополнительных глав';
const worldProfiles = {
  romantic_story: {
    title: 'Romantic Story',
    env: 'Современный теплый мир, где романтика вплетена в повседневность: кафе, вокзалы, набережные, кухни, маленькие поездки, праздники и знакомые улицы становятся сценами выбора. Чудо работает как romcom-совпадение: задержка, потерянная вещь, случайная встреча, общий маршрут или добрый посредник подталкивают героев услышать друг друга, но не решают за них. Если герои уже пара, история не заставляет их влюбляться с нуля, а показывает новый виток близости через память, заботу и честный разговор.',
    rel: 'ромком-пара на равных: взаимное притяжение или уже существующая нежность + внешняя цель + несовпадение ожиданий; доверие растет через совместное дело, смешные сбои, заботу в мелочах и выбор сказать правду',
    motifs: 'meet-cute или узнаваемое первое столкновение; общий маршрут/дело; mistaken assumptions без жестокости; личный символ пары; помощь другу или незнакомцу; почти-признание; камерный grand gesture; ищем идеальный подарок - находим способ увидеть другого',
    visual: 'Warm romantic storybook realism, soft daylight or evening glow, intimate everyday locations, expressive but natural gestures, gentle humor, small symbolic object in frame, cozy textures, readable faces and silhouettes, balanced composition, tender cinematic atmosphere without melodrama.',
    conflict: 'страх уязвимости и привычка контролировать впечатление против честности, принятия помощи и выбора быть рядом',
    extra: 'Используй классическую romcom-структуру без копирования известных сюжетов: 1) личный ритуал/обычный мир пары или героя; 2) неловкое теплое столкновение с проблемой; 3) вынужденное совместное дело вокруг места или артефакта; 4) серия маленьких побед и смешных осложнений, где забота проявляется действиями; 5) midpoint - момент почти-признания или ясного мы команда; 6) misunderstanding/low point без измен, унижения и жестокости; 7) выбор уязвимости; 8) теплый жест и новый общий ритуал. Любовь должна становиться убедительной через наблюдательность, уважение границ, конкретные детали и короткие живые диалоги.',
  },
  adventure_classic: {
    title: 'Adventure Classic',
    env: 'Мир дорог, открытий и смелых решений. Здесь важно не место, а движение вперед - по воде, по суше или в воздухе. Герои действуют спонтанно, доверяют случаю и находят приключения там, где другие прошли мимо. Все вокруг полно света, ветра и неожиданностей. Атмосфера бодрая и свободная, с чувством риска, юмора и предвкушения следующего поворота.',
    rel: 'неидеальная команда, равное партнерство; импровизация и взаимовыручка',
    motifs: 'поиск артефакта; загадки и ловушки; ищем внешнее - находим внутреннее',
    visual: 'Bold adventure framing, strong sun and shadow contrasts; dynamic angles and gestures; warm natural palette with ocean or sky accents; sense of motion, curiosity, and open horizon.',
    conflict: 'риск и выбор пути проверяют доверие команды; гордость я сам против умения опереться на напарника',
  },
  hogwarts_world: {
    title: 'Hogwarts World',
    env: 'Наши дни, 2026 год, скрытый магический слой мира: школа или интернат чародейства, старые башни и коридоры, портреты, движущиеся лестницы или переходы, кабинеты, библиотека, теплая столовая, двор под снегом. Атмосфера уютная: хвоя, теплый свет свечей и фонарей, запах мандаринов или пряностей, пар от дыхания. Магия реальна, но работает как мягкое чудо: подталкивает, помогает заметить, открыть, найти, согреть, соединить людей, но не подменяет выбор героя.',
    rel: 'команда учеников, тихий наставник или подталкивающий трикстер; доверие растет через совместный риск, добрый поступок и умение заметить другого',
    motifs: 'магическая школа; скрытые переходы; письма и портреты; школьный ритуал; зимний свет; артефакт с тайным правилом; чудо как подсказка, а не готовое решение',
    visual: 'Warm magical boarding-school atmosphere, old towers and corridors, candlelight, lantern glow, pine branches, frosted windows, falling snow, cozy dining hall, library shelves, courtyard under winter dusk; readable silhouettes, figurative storybook composition, soft bokeh, no horror/grunge, no 3D/collage.',
    conflict: 'срыв важного школьного или городского ритуала против способности героев понять мотив антагониста и сохранить людей важнее самого ритуала',
    extra: 'Антагонист пытается сорвать важный ритуал или событие школы/города: посвящение, зимний бал, церемонию огня, ночь фонарей, клятву класса, вручение знака, открытие зала или возврат света. В финале антагонист преображается: понятна причина, сделан добрый жест, наступает примирение. Не добавляй каноничные имена, названия школ, факультетов, заклинаний, игр, мест и любые узнаваемые элементы чужой франшизы дословно; только общее ощущение жанра школа чародейства.',
  },
  fantasy_epic: {
    title: 'Fantasy Epic',
    env: 'Мир древних дорог, городов, крепостей, лесов и гор, где магия встроена в быт и всегда имеет понятное правило: цену, условие, запрет или ограничение. Большие события начинаются с простой беды рядом с героями: пропажа, сломанный обряд, опасная дорога, нарушенная клятва или просьба о помощи. Ставки могут быть высокими, но каждая сцена должна держаться на конкретных действиях, решениях и деталях места.',
    rel: 'наставник и ученик или небольшая команда; доверие растет через полезные поступки, честный разговор, взаимную помощь и выбор в пользу другого',
    motifs: 'карта или ключ; клятва; испытание; тайная дорога; страж порога; артефакт с правилом; антагонист с понятной причиной; внешняя цель раскрывает страх или слабое место героя',
    visual: 'Misty depth, textured painterly surfaces, layered light and shadow; cool palette with warm highlights; balanced scale and grandeur; clear composition, quiet tension, readable practical details of the place and artifact.',
    conflict: 'герой хочет избежать ответственности или решить все силой, но должен выбрать честный поступок, защитить близких и понять цену магии',
    extra: 'Сохрани эпическую арку, но пиши проще и предметнее. Не перегружай текст метафорами, символами и словами вроде судьба, тьма, свет, сердце, вечность, древняя сила. Используй такие слова редко и только когда они прямо связаны с действием сцены. На каждой странице достаточно 1-2 ярких образов; остальное должно держаться на поступках, диалоге, конкретных деталях места, правилах магии и последствиях выбора. Каждая глава: ясная задача, осложнение, открытие, решение героя.',
  },
  cyberpunk_dream: {
    title: 'Cyberpunk Dream',
    env: 'Мир, где технологии проникли во все сферы жизни, а границы между реальным и виртуальным размылись. Города светятся искусственным светом, сети управляют привычками, и человек все чаще сталкивается с решениями, которые принимают машины. Законы слабы, корпорации сильны, но в каждом еще остается место выбору - оставаться живым, несмотря на холод систем. Атмосфера напряженная и электрическая, с ощущением скорости, одиночества и поиска смысла в мире без сна.',
    rel: 'холодная близость; доверие под вопросом; сделки и цена автономии',
    motifs: 'бунт против системы; взлом; тело против машины; реальность против симуляции',
    visual: 'High-contrast neon, wet reflections, sharp silhouettes; diffuse screen glow, hanging cables, faint rain haze; blue-violet base with warm amber or magenta accents; cinematic depth, sense of motion and isolation.',
    conflict: 'свобода против контроля и ее личная цена',
  },
};
worldProfiles.disney_light = worldProfiles.romantic_story;
const worldProfile = worldProfiles[worldKey] || worldProfiles.romantic_story;
const worldBrief = [
  'Название мира: ' + worldProfile.title,
  'Среда и законы: ' + worldProfile.env,
  'Отношения: ' + worldProfile.rel,
  'Мотивы: ' + worldProfile.motifs,
  'Конфликт: ' + worldProfile.conflict,
  'Визуальный язык для story bible и сцен: ' + worldProfile.visual,
  worldProfile.extra || '',
].filter(Boolean).join('\n');
const heroes = (order.heroes || []).filter((hero) => hero.name || hero.description || hero.relation).map((hero) => 'Герой ' + hero.n + ': ' + (hero.name || 'без имени') + ' - ' + (hero.description || 'описание не задано') + ' - ' + (hero.relation || 'роль не задана')).join('\n');
const systemText = 'Ты - автор персональных книг Fairyteller. Пиши на русском языке, без буквы е с точками. Тон: современная ясная проза, живые сцены, теплые детали, легкий юмор, без канцелярита и мета-комментариев. Герои уже заданы пользователем; не меняй имена, факты, отношения и возраст. Не добавляй известных copyrighted персонажей и не копируй чужие вселенные. Для романтической истории держи скромный уровень: близость через поступки, взгляд, заботу, неловкость, выбор и диалог, без эротики. Если герои уже пара, не делай вид, что они только познакомились: строй арку нового сближения или важного совместного жеста. Для фэнтези избегай перегретой поэтичности: не нанизывай метафоры, не превращай каждое чувство в символ, пиши простыми фразами через действие, предметы, правила магии и решения героя. Верни только валидный JSON. Внутри JSON-строк не используй кавычки-елочки, markdown, списки и переносы строк; диалоги оформляй через тире.';
const userText = 'Создай story bible и ПЕРВУЮ главу персональной книги. Полная книга рассчитана примерно на ' + lengthTarget + ' знаков и ' + chaptersTarget + ' глав. Остальные главы пока не писать полностью: нужен ' + laterChaptersText + ', чтобы первая глава была началом цельной истории.\n\n' +
  'Выбранный мир: ' + worldKey + '\n' + worldBrief + '\n\n' +
  'Новогодний/праздничный режим: ' + (order.newyearMode ? 'да, вплети праздник/зиму/подарок органично' : 'нет') + '\n' +
  'Место действия: ' + (order.location || 'не задано') + '\n' +
  'Важный предмет/артефакт: ' + (order.artifact || 'не задан') + '\n' +
  'Пользователь просит название: ' + (order.titleNeed ? 'да, сделай bookTitle особенно выразительным' : 'нет, но bookTitle все равно нужен для структуры') + '\n' +
  'Язык: ' + (order.language || 'ru') + '\n' +
  'Стиль иллюстраций: ' + (order.illustrationStyle || 'storybook') + '\n\n' +
  'Персонажи:\n' + (heroes || 'Герои не заданы; создай нейтральную пару/команду без новых анкетных подробностей.') + '\n\n' +
  'Требования к первой главе:\n' +
  '- Это глава 1 из ' + chaptersTarget + '. Она должна быть настоящей литературной главой и сразу лечь на печатные страницы.\n' +
  '- ' + firstChapterTextBlockTarget + ' текстовых блоков для верстки, каждый 780-1050 знаков, идеал 850-950 знаков, каждый блок 2-3 плотных абзаца. Блок короче 740 знаков считается браком: перепиши его подробнее через действие, детали и короткий диалог.\n' +
  '- Выбранный мир должен быть заметен в событиях, деталях и конфликте, а не только назван в bible.\n' +
  '- Место действия должно появиться в осязаемых деталях первой главы.\n' +
  '- Важный предмет должен быть виден и повлиять на действие первой главы.\n' +
  '- В главе должны быть: ритуал/контекст героев, первое столкновение с проблемой, локация в деталях, предмет в действии, микро-поворот отношений/доверия и мягкий крючок на главу 2.\n' +
  '- Диалоги короткие, не больше 4-6 реплик на главу.\n' +
  '- Не используй заголовки внутри textBlocks, markdown, маркеры списков и служебные пометки.\n' +
  '- Не вставляй переносы строк внутри значений JSON; каждый textBlocks[i] должен быть одной JSON-строкой.\n' +
  '- chapter1.summary должен быть визуальным ТЗ для иллюстрации: кто в кадре, где, что делает, предмет, свет, ракурс, настроение; 260-380 знаков, без будущих спойлеров и без слов про стиль.\n\n' +
  'Верни JSON строго по schema. chapterPlan должен содержать ровно ' + chaptersTarget + ' элементов: [' + planShape + '].';
const responseSchema = {
  type: 'OBJECT',
  properties: {
    bookTitle: { type: 'STRING' },
    subtitle: { type: 'STRING' },
    coverSummary: { type: 'STRING' },
    storyBible: {
      type: 'OBJECT',
      properties: {
        world: { type: 'STRING' },
        location: { type: 'STRING' },
        artifact: { type: 'STRING' },
        tone: { type: 'STRING' },
        throughline: { type: 'STRING' },
      },
      required: ['world', 'location', 'artifact', 'tone', 'throughline'],
    },
    chapterPlan: {
      type: 'ARRAY',
      items: {
        type: 'OBJECT',
        properties: { n: { type: 'NUMBER' }, title: { type: 'STRING' }, beat: { type: 'STRING' } },
        required: ['n', 'title', 'beat'],
      },
    },
    chapter1: {
      type: 'OBJECT',
      properties: {
        title: { type: 'STRING' },
        summary: { type: 'STRING' },
        textBlocks: { type: 'ARRAY', items: { type: 'STRING' } },
      },
      required: ['title', 'summary', 'textBlocks'],
    },
  },
  required: ['bookTitle', 'subtitle', 'coverSummary', 'storyBible', 'chapterPlan', 'chapter1'],
};
const geminiRequest = {
  systemInstruction: { parts: [{ text: systemText }] },
  contents: [{ role: 'user', parts: [{ text: userText }] }],
  generationConfig: {
    temperature: 0.65,
    topP: 0.9,
    maxOutputTokens: 9000,
    responseMimeType: 'application/json',
    responseSchema,
  },
};
return [{ json: { ...item, jobId, geminiModel: 'gemini-2.5-flash', worldKey, worldProfile, chaptersTarget, lengthTarget, chapterTextBlockTargets, firstChapterTextBlockTarget, geminiRequest } }];

const source = $('Build First Chapter Prompt').first().json;
const jobId = source.jobId;
const model = source.geminiModel || 'gemini-2.5-flash';
const url = 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent';
const apiToken = $env.FAIRYTELLER_API_TOKEN;
const apiKey = $env.GEMINI_API_KEY;
const jobUrl = 'https://fairyteller.ru/api/fairyteller/jobs/' + jobId;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function errorStatus(error) {
  return Number(error?.response?.statusCode || error?.response?.status || error?.statusCode || error?.status || 0);
}

function errorText(error) {
  const body = error?.response?.body || error?.cause?.response?.body;
  const message = typeof body === 'string'
    ? body
    : body?.error?.message || body?.message || error?.message || 'unknown error';
  return String(message).replace(/\s+/g, ' ').trim().slice(0, 500);
}

function shouldRetry(error) {
  const status = errorStatus(error);
  if ([408, 409, 425, 429].includes(status)) return true;
  if (status >= 500) return true;
  const text = errorText(error).toLowerCase();
  return text.includes('timeout') || text.includes('temporarily') || text.includes('high demand') || text.includes('unavailable') || text.includes('rate');
}

async function patchJob(patch) {
  if (!jobId || !apiToken) return;
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: jobUrl,
    headers: {
      Authorization: 'Bearer ' + apiToken,
      'Content-Type': 'application/json',
    },
    body: patch,
    json: true,
    timeout: 30000,
  });
}

async function markFailed(error) {
  const providerMessage = errorText(error);
  const userMessage = 'Не удалось написать первую главу: Gemini временно перегружен. Попробуйте запустить генерацию еще раз через пару минут.';
  try {
    await patchJob.call(this, {
      status: 'failed',
      stage: 'text',
      progress: 15,
      message: userMessage,
      error: {
        message: userMessage,
        provider: 'gemini',
        node: 'Generate First Chapter with Gemini',
        cause: providerMessage,
      },
      artifacts: {
        text: { status: 'failed', error: userMessage },
      },
    });
  } catch (patchError) {
    console.log('Failed to mark job as failed after Gemini error: ' + errorText(patchError));
  }
}

if (!apiKey) throw new Error('GEMINI_API_KEY is not configured');

const waits = [10000, 20000, 35000, 55000];
let lastError;
for (let attempt = 0; attempt <= waits.length; attempt += 1) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url,
      headers: {
        'x-goog-api-key': apiKey,
        'Content-Type': 'application/json',
      },
      body: source.geminiRequest,
      json: true,
      timeout: 180000,
    });
    return [{ json: response }];
  } catch (error) {
    lastError = error;
    const canRetry = attempt < waits.length && shouldRetry(error);
    console.log('Gemini first chapter attempt ' + (attempt + 1) + ' failed: ' + errorText(error) + (canRetry ? '; retrying' : '; no retry'));
    if (!canRetry) break;
    await sleep(waits[attempt]);
  }
}

await markFailed.call(this, lastError);
throw new Error('Gemini first chapter request failed after retries: ' + errorText(lastError));

const source = $('Build First Chapter Prompt').first().json;
const response = $input.first().json;
const FIRST_CHAPTER_TEXT_BLOCKS = Number(source.firstChapterTextBlockTarget || source.chapterTextBlockTargets?.[1] || 4);

function collectText(value) {
  return String(value?.candidates?.[0]?.content?.parts?.map((part) => part.text || '').join('') || '').trim();
}

function extractJsonCandidate(text) {
  let candidate = String(text || '').trim().replace(/^\uFEFF/, '');
  const fence = candidate.match(/^\`\`\`(?:json)?\s*([\s\S]*?)\s*\`\`\`$/i);
  if (fence) candidate = fence[1].trim();
  const firstBrace = candidate.indexOf('{');
  const lastBrace = candidate.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) candidate = candidate.slice(firstBrace, lastBrace + 1);
  return candidate;
}

function escapeControlCharsInsideStrings(text) {
  let result = '';
  let inString = false;
  let escaped = false;
  for (const char of text) {
    if (escaped) {
      result += char;
      escaped = false;
      continue;
    }
    if (char === '\\') {
      result += char;
      escaped = true;
      continue;
    }
    if (char === '"') {
      inString = !inString;
      result += char;
      continue;
    }
    if (inString && char === '\n') {
      result += '\\n';
      continue;
    }
    if (inString && char === '\r') {
      result += '\\r';
      continue;
    }
    if (inString && char === '\t') {
      result += '\\t';
      continue;
    }
    result += char;
  }
  return result;
}

function repairLikelyJson(text) {
  return String(text || '')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/"\s*\n\s*"/g, '"\n,"')
    .replace(/}\s*\n\s*"/g, '}\n,"')
    .replace(/]\s*\n\s*"/g, ']\n,"');
}

function parseGeminiJson(raw) {
  const candidate = extractJsonCandidate(raw);
  const escaped = escapeControlCharsInsideStrings(candidate);
  const attempts = [candidate, escaped, repairLikelyJson(escaped)];
  let lastError;
  for (const attempt of attempts) {
    try {
      return JSON.parse(attempt);
    } catch (error) {
      lastError = error;
    }
  }
  for (const looseAttempt of [candidate, escaped, repairLikelyJson(escaped), raw]) {
    const fallback = parseLooseGeminiJson(looseAttempt);
    if (fallback) return fallback;
  }
  throw new Error('Gemini first chapter response was not valid JSON after repair: ' + (lastError?.message || 'unknown parse error'));
}

function readStringField(text, key) {
  const re = new RegExp('"' + key + '"\\s*:\\s*"([\\s\\S]*?)"\\s*(?:,|\\n\\s*"|\\n\\s*[}\\]])');
  const match = String(text || '').match(re);
  if (!match) return '';
  return match[1].replace(/\\n/g, ' ').replace(/\\"/g, '"').replace(/\\\\/g, '\\').replace(/\s+/g, ' ').trim();
}

function splitRawTextIntoBlocks(text) {
  let raw = String(text || '').replaceAll('\\n', ' ').replaceAll('\n', ' ');
  const textBlocksIndex = raw.indexOf('"textBlocks"');
  const chapterIndex = raw.indexOf('"chapter1"');
  if (textBlocksIndex >= 0) raw = raw.slice(textBlocksIndex);
  else if (chapterIndex >= 0) raw = raw.slice(chapterIndex);
  raw = raw
    .replace(/\"/g, '"')
    .replace(/"(?:bookTitle|subtitle|coverSummary|storyBible|chapterPlan|chapter1|title|summary|textBlocks|world|location|artifact|tone|throughline|n|beat)"\s*:?/g, ' ')
    .replace(/[{}\[\],]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (raw.length < 180) return [];
  const minSize = Math.max(100, Math.floor(raw.length / 8));
  const target = Math.max(minSize, Math.floor(raw.length / FIRST_CHAPTER_TEXT_BLOCKS));
  const blocks = [];
  let rest = raw;
  while (blocks.length < FIRST_CHAPTER_TEXT_BLOCKS - 1 && rest.length > target) {
    let cut = rest.lastIndexOf('. ', target + 220);
    if (cut < target - 220) cut = rest.lastIndexOf('! ', target + 220);
    if (cut < target - 220) cut = rest.lastIndexOf('? ', target + 220);
    if (cut < target - 220) cut = rest.indexOf('. ', target);
    if (cut < 0 || cut > rest.length - minSize) cut = Math.min(rest.length - minSize, target);
    const block = rest.slice(0, cut + 1).replace(/\s+/g, ' ').trim();
    if (block) blocks.push(block);
    rest = rest.slice(cut + 1).replace(/\s+/g, ' ').trim();
  }
  if (rest) blocks.push(rest.replace(/\s+/g, ' ').trim());
  while (blocks.length < FIRST_CHAPTER_TEXT_BLOCKS && blocks.some((block) => block.length > minSize * 2)) {
    const index = blocks.reduce((maxIndex, block, currentIndex) => block.length > blocks[maxIndex].length ? currentIndex : maxIndex, 0);
    const block = blocks[index];
    let cut = block.lastIndexOf('. ', Math.floor(block.length / 2) + 120);
    if (cut < Math.floor(block.length / 2) - 120) cut = Math.floor(block.length / 2);
    blocks.splice(index, 1, block.slice(0, cut + 1).trim(), block.slice(cut + 1).trim());
  }
  return blocks.slice(0, FIRST_CHAPTER_TEXT_BLOCKS).map((block) => block.replace(/\s+/g, ' ').trim()).filter(Boolean);
}

function extractStringValuesAfterKey(text, key, limit = FIRST_CHAPTER_TEXT_BLOCKS) {
  const sourceText = String(text || '');
  const keyIndex = sourceText.indexOf('"' + key + '"');
  if (keyIndex < 0) return [];
  const arrayStart = sourceText.indexOf('[', keyIndex);
  if (arrayStart < 0) return [];
  const values = [];
  let i = arrayStart + 1;
  while (i < sourceText.length && values.length < limit) {
    while (i < sourceText.length && sourceText[i] !== '"') {
      if (sourceText[i] === ']' && values.length > 0) return values;
      i += 1;
    }
    if (i >= sourceText.length) break;
    i += 1;
    let value = '';
    let escaped = false;
    while (i < sourceText.length) {
      const char = sourceText[i];
      if (escaped) {
        value += char === 'n' ? ' ' : char;
        escaped = false;
        i += 1;
        continue;
      }
      if (char === '\\') {
        escaped = true;
        i += 1;
        continue;
      }
      if (char === '"') {
        i += 1;
        break;
      }
      value += char;
      i += 1;
    }
    const cleaned = value.replace(/\s+/g, ' ').trim();
    if (cleaned) values.push(cleaned);
    if (i >= sourceText.length && values.length > 0) return values;
  }
  return values;
}

function parseLooseGeminiJson(text) {
  const title = readStringField(text, 'bookTitle');
  const subtitle = readStringField(text, 'subtitle');
  const coverSummary = readStringField(text, 'coverSummary');
  const chapterTitle = readStringField(text, 'title') || title || 'Первая глава';
  const chapterSummary = readStringField(text, 'summary') || coverSummary;
  let blocks = extractStringValuesAfterKey(text, 'textBlocks', FIRST_CHAPTER_TEXT_BLOCKS);
  if (blocks.length !== FIRST_CHAPTER_TEXT_BLOCKS) {
    const blocksMatch = String(text || '').match(/"textBlocks"\s*:\s*\[([\s\S]*?)(?:\]\s*(?:,|\n\s*})|$)/);
    if (blocksMatch) {
      const stringRe = /"((?:\\.|[^"\\])*)"/g;
      let match;
      const regexBlocks = [];
      while ((match = stringRe.exec(blocksMatch[1])) && regexBlocks.length < FIRST_CHAPTER_TEXT_BLOCKS) {
        const value = match[1].replace(/\\n/g, ' ').replace(/\\"/g, '"').replace(/\\\\/g, '\\').replace(/\s+/g, ' ').trim();
        if (value) regexBlocks.push(value);
      }
      if (regexBlocks.length === FIRST_CHAPTER_TEXT_BLOCKS) blocks = regexBlocks;
    }
  }
  if (blocks.length !== FIRST_CHAPTER_TEXT_BLOCKS) {
    const recoveredBlocks = splitRawTextIntoBlocks(text);
    if (recoveredBlocks.length === FIRST_CHAPTER_TEXT_BLOCKS) blocks = recoveredBlocks;
  }
  if (blocks.length !== FIRST_CHAPTER_TEXT_BLOCKS && blocks.length > 0) {
    const joined = blocks.join(' ');
    const resplit = splitRawTextIntoBlocks(joined);
    if (resplit.length === FIRST_CHAPTER_TEXT_BLOCKS) blocks = resplit;
  }
  if (blocks.length !== FIRST_CHAPTER_TEXT_BLOCKS) return null;
  return {
    bookTitle: title,
    subtitle,
    coverSummary,
    storyBible: {
      world: source.worldKey || source.order?.world || '',
      location: source.order?.location || '',
      artifact: source.order?.artifact || '',
      tone: 'Recovered from Gemini loose JSON response',
      throughline: coverSummary || chapterSummary || '',
      worldTitle: source.worldProfile?.title || '',
      worldEnv: source.worldProfile?.env || '',
      worldRel: source.worldProfile?.rel || '',
      worldMotifs: source.worldProfile?.motifs || '',
      worldDramaturgy: source.worldProfile?.extra || '',
      worldConflict: source.worldProfile?.conflict || '',
      worldVisual: source.worldProfile?.visual || '',
    },
    chapterPlan: Array.from({ length: source.chaptersTarget || source.order?.chapters || 5 }, (_, index) => ({ n: index + 1, title: 'Глава ' + (index + 1), beat: index === 0 ? chapterSummary : '' })),
    chapter1: { title: chapterTitle, summary: chapterSummary, textBlocks: blocks },
  };
}


async function markTextFailed(error, nodeName) {
  const message = 'Не удалось подготовить первую главу для книги. Попробуйте запустить генерацию еще раз.';
  const cause = String(error?.message || 'unknown error').replace(/\s+/g, ' ').trim().slice(0, 500);
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: 'https://fairyteller.ru/api/fairyteller/jobs/' + source.jobId,
      headers: {
        Authorization: 'Bearer ' + $env.FAIRYTELLER_API_TOKEN,
        'Content-Type': 'application/json',
      },
      body: {
        status: 'failed',
        stage: 'text',
        progress: 15,
        message,
        error: { message, provider: 'gemini', node: nodeName, cause },
        artifacts: { text: { status: 'failed', error: message } },
      },
      json: true,
      timeout: 30000,
    });
  } catch (patchError) {
    console.log('Failed to mark job as failed after normalize error: ' + String(patchError?.message || patchError));
  }
}

try {
const rawText = collectText(response);
if (!rawText) throw new Error('Gemini first chapter response was empty');
const generated = parseGeminiJson(rawText);
const chapter1 = generated.chapter1 || {};
const textBlocks = Array.isArray(chapter1.textBlocks)
  ? chapter1.textBlocks.map((block) => String(block || '').replace(/\s+/g, ' ').trim()).filter(Boolean)
  : [];
if (textBlocks.length !== FIRST_CHAPTER_TEXT_BLOCKS) throw new Error('Expected ' + FIRST_CHAPTER_TEXT_BLOCKS + ' chapter 1 text blocks, got ' + textBlocks.length);
const fullChapterText = textBlocks.join('\n\n');
const preview = {
  chapter: 1,
  title: chapter1.title || generated.bookTitle || 'Первая глава',
  summary: chapter1.summary || '',
  text: fullChapterText,
  imageStatus: 'pending',
};
const text = {
  bible: {
    ...(generated.storyBible || {}),
    world: generated.storyBible?.world || source.worldKey || source.order?.world || '',
    location: generated.storyBible?.location || source.order?.location || '',
    artifact: generated.storyBible?.artifact || source.order?.artifact || '',
    bookTitle: generated.bookTitle || '',
    subtitle: generated.subtitle || '',
    coverSummary: generated.coverSummary || '',
    chapterPlan: Array.isArray(generated.chapterPlan) ? generated.chapterPlan.slice(0, source.chaptersTarget || source.order?.chapters || 5) : [],
    worldTitle: generated.storyBible?.worldTitle || source.worldProfile?.title || '',
    worldEnv: generated.storyBible?.worldEnv || source.worldProfile?.env || '',
    worldRel: generated.storyBible?.worldRel || source.worldProfile?.rel || '',
    worldMotifs: generated.storyBible?.worldMotifs || source.worldProfile?.motifs || '',
    worldDramaturgy: generated.storyBible?.worldDramaturgy || source.worldProfile?.extra || '',
    worldConflict: generated.storyBible?.worldConflict || source.worldProfile?.conflict || '',
    worldVisual: generated.storyBible?.worldVisual || source.worldProfile?.visual || '',
  },
  preview,
  chapterTextBlockTargets: source.chapterTextBlockTargets || { 1: FIRST_CHAPTER_TEXT_BLOCKS, 2: 4, 3: 6, 4: 6, 5: 5 },
  chapters: [{ n: 1, title: preview.title, summary: preview.summary, textBlocks, text: fullChapterText, status: 'ready' }],
  generation: { provider: 'gemini', model: source.geminiModel || 'gemini-2.5-flash', responseId: response.responseId || null },
};
return [{ json: { ...source, status: 'chapter_1_ready', text, pipeline: { next: 'fairyteller_visuals_and_full_text', previewEnabled: false, firstChapterImagePriority: true, fullBookAutoStart: true } } }];
} catch (error) {
  await markTextFailed.call(this, error, 'Normalize First Chapter');
  throw error;
}
